import{c as a,Q as n,j as i,m as p}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"多平台导出、D3D12 与增量补丁","description":"","frontmatter":{},"headers":[],"relativePath":"godotLearning/26-多平台导出-D3D12与增量补丁.md","filePath":"godotLearning/26-多平台导出-D3D12与增量补丁.md","lastUpdated":1780014601000}'),e={name:"godotLearning/26-多平台导出-D3D12与增量补丁.md"};function t(l,s,h,d,o,c){return n(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="多平台导出、d3d12-与增量补丁" tabindex="-1">多平台导出、D3D12 与增量补丁 <a class="header-anchor" href="#多平台导出、d3d12-与增量补丁" aria-label="Permalink to &quot;多平台导出、D3D12 与增量补丁&quot;">​</a></h1><p>能在编辑器里跑,不等于能发给玩家。导出要处理平台、渲染后端、纹理压缩、签名、补丁和资源包。</p><blockquote><p>一句话先记住:<strong>导出配置是工程资产,<code>export_presets.cfg</code> 要进版本控制。</strong></p></blockquote><hr><h2 id="一、先建-export-preset" tabindex="-1">一、先建 Export Preset <a class="header-anchor" href="#一、先建-export-preset" aria-label="Permalink to &quot;一、先建 Export Preset&quot;">​</a></h2><p>Godot 导出配置存在:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export_presets.cfg</span></span></code></pre></div><p>它记录:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>导出平台</span></span>
<span class="line"><span>包含/排除哪些资源</span></span>
<span class="line"><span>图标和版本信息</span></span>
<span class="line"><span>渲染后端</span></span>
<span class="line"><span>签名配置</span></span>
<span class="line"><span>纹理压缩</span></span></code></pre></div><p>不要只在自己机器的 Export 窗口里点完就算。CI 和别人接手项目都需要这份文件。</p><hr><h2 id="二、先做三个目标" tabindex="-1">二、先做三个目标 <a class="header-anchor" href="#二、先做三个目标" aria-label="Permalink to &quot;二、先做三个目标&quot;">​</a></h2><p>独立 2D 项目常见目标:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Windows</span></span>
<span class="line"><span>macOS / Linux</span></span>
<span class="line"><span>Web 或 Android</span></span></code></pre></div><p>不要一开始承诺全平台。每个平台都要测试输入、存档、字体、性能、窗口、音频。</p><hr><h2 id="三、windows-的-d3d12" tabindex="-1">三、Windows 的 D3D12 <a class="header-anchor" href="#三、windows-的-d3d12" aria-label="Permalink to &quot;三、Windows 的 D3D12&quot;">​</a></h2><p>Godot 4.6 的 Windows 新项目默认倾向 D3D12。老项目升级时不要假设自动切了。</p><p>导出前至少测:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D3D12</span></span>
<span class="line"><span>Vulkan</span></span>
<span class="line"><span>Compatibility</span></span></code></pre></div><p>如果玩家机器驱动太旧,需要有 fallback 思路。2D 项目通常不依赖特别新的 GPU 功能,但 shader、光照、GDExtension 动态库都要实际跑一遍。</p><hr><h2 id="四、pck-是资源包" tabindex="-1">四、PCK 是资源包 <a class="header-anchor" href="#四、pck-是资源包" aria-label="Permalink to &quot;四、PCK 是资源包&quot;">​</a></h2><p>Godot 导出通常会得到:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>game.exe</span></span>
<span class="line"><span>game.pck</span></span></code></pre></div><p><code>.pck</code> 放资源。可执行文件启动后加载它。</p><p>运行时也可以加载额外资源包:</p><div class="language-gdscript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gdscript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ProjectSettings</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">load_resource_pack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user://mods/example.pck&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这条路可以做 DLC、mod、补丁。</p><hr><h2 id="五、增量补丁" tabindex="-1">五、增量补丁 <a class="header-anchor" href="#五、增量补丁" aria-label="Permalink to &quot;五、增量补丁&quot;">​</a></h2><p>补丁不要总是让玩家重新下载完整包。Godot 4.6 支持 delta patch PCK,补丁只包含差异。</p><p>实际策略:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.0.0 完整包</span></span>
<span class="line"><span>1.0.1 patch pck</span></span>
<span class="line"><span>1.0.2 patch pck</span></span></code></pre></div><p>启动时按顺序加载补丁:</p><div class="language-gdscript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gdscript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> load_patches</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> patches </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;user://patches/patch_1_0_1.pck&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;user://patches/patch_1_0_2.pck&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> path </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> patches:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FileAccess</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file_exists</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path):</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">            ProjectSettings</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">load_resource_pack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path)</span></span></code></pre></div><p>补丁机制很强,但也会增加发布复杂度。小项目早期直接发完整包也可以,等包体变大再上补丁。</p><hr><h2 id="六、web-导出要单独测" tabindex="-1">六、Web 导出要单独测 <a class="header-anchor" href="#六、web-导出要单独测" aria-label="Permalink to &quot;六、Web 导出要单独测&quot;">​</a></h2><p>Web 不是“小号 PC”。</p><p>重点检查:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器是否允许音频自动播放</span></span>
<span class="line"><span>存档是否真的写进 IndexedDB</span></span>
<span class="line"><span>字体是否全部打包</span></span>
<span class="line"><span>纹理格式是否支持</span></span>
<span class="line"><span>服务器 HTTP header 是否正确</span></span>
<span class="line"><span>加载首屏是否过大</span></span></code></pre></div><p>Web 上 <code>user://</code> 是浏览器存储,不要按桌面文件系统思路设计。</p><hr><h2 id="七、移动端重点" tabindex="-1">七、移动端重点 <a class="header-anchor" href="#七、移动端重点" aria-label="Permalink to &quot;七、移动端重点&quot;">​</a></h2><p>Android / iOS 重点不是能不能打包,而是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触屏输入</span></span>
<span class="line"><span>安全区</span></span>
<span class="line"><span>返回键</span></span>
<span class="line"><span>暂停/恢复生命周期</span></span>
<span class="line"><span>纹理压缩</span></span>
<span class="line"><span>包名和签名</span></span>
<span class="line"><span>性能和发热</span></span></code></pre></div><p>移动端先做最小导出测试,别等项目最后才发现 UI 全贴边、字体太小、触控按钮挡住游戏内容。</p><hr><h2 id="八、导出前检查" tabindex="-1">八、导出前检查 <a class="header-anchor" href="#八、导出前检查" aria-label="Permalink to &quot;八、导出前检查&quot;">​</a></h2><ul><li><code>export_presets.cfg</code> 已提交。</li><li>export template 版本和编辑器版本一致。</li><li>Windows 至少测 D3D12 和 Vulkan。</li><li>存档路径在导出版可写。</li><li>字体在所有目标平台都有。</li><li>GDExtension 动态库按平台打包。</li><li>Web 版本真实部署到 HTTP 服务测试,不是只打开本地文件。</li><li>补丁策略清楚:完整包还是 patch PCK。</li></ul><hr><h2 id="常见坑" tabindex="-1">常见坑 <a class="header-anchor" href="#常见坑" aria-label="Permalink to &quot;常见坑&quot;">​</a></h2><p><strong>坑 1:只在编辑器里测试。</strong></p><p>导出版资源路径、日志、存档、性能都可能不同。</p><p><strong>坑 2:忘记 export template 版本。</strong></p><p>编辑器和模板版本不一致会出奇怪问题。</p><p><strong>坑 3:Web 本地打开 HTML。</strong></p><p>很多浏览器能力需要 HTTP 环境。用本地服务器测。</p><p><strong>坑 4:补丁覆盖顺序混乱。</strong></p><p>patch PCK 要有明确版本顺序。</p><hr><p>下一篇讲本地化、字体和输入设备适配。</p>`,63)])])}const g=a(e,[["render",t]]);export{k as __pageData,g as default};
